import{_ as o,c as a,o as e,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"토큰 통계: 비용 모니터링과 데이터 분석 | Antigravity Manager","description":"Token Stats 통계 기능 사용 방법을 학습합니다. 응답에서 토큰 데이터 추출, 모델 및 계정별 사용량 분석, Top 리스트로 가장 비싼 모델과 계정을 찾아내고, 통계 누락 문제를 해결하는 방법을 배웁니다.","frontmatter":{"title":"토큰 통계: 비용 모니터링과 데이터 분석 | Antigravity Manager","sidebarTitle":"한눈에 가장 비싼 것 파악","subtitle":"토큰 통계: 비용 모니터링과 데이터 분석","description":"Token Stats 통계 기능 사용 방법을 학습합니다. 응답에서 토큰 데이터 추출, 모델 및 계정별 사용량 분석, Top 리스트로 가장 비싼 모델과 계정을 찾아내고, 통계 누락 문제를 해결하는 방법을 배웁니다.","tags":["Token Stats","비용","모니터링","SQLite","사용량 통계"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":7},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),d={name:"ko/lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function l(s,t,i,n,u,c){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="token-stats-비용-관점의-통계-기준-및-차트-해석" tabindex="-1">Token Stats: 비용 관점의 통계 기준 및 차트 해석 <a class="header-anchor" href="#token-stats-비용-관점의-통계-기준-및-차트-해석" aria-label="Permalink to &quot;Token Stats: 비용 관점의 통계 기준 및 차트 해석&quot;">​</a></h1><p>이미 클라이언트를 Antigravity Tools에 연결했지만, &quot;누가 돈을 쓰고 있는지, 어디서 비싼지, 특정 모델이 갑자기 급증했는지&quot;는 직관으로 판단하기 어렵습니다. 이 수업에서는 Token Stats 페이지의 데이터 기준을 명확히 설명하고, 차트로 빠르게 비용 문제를 찾는 방법을 가르칩니다.</p><h2 id="수업을-마치면-할-수-있는-것" tabindex="-1">수업을 마치면 할 수 있는 것 <a class="header-anchor" href="#수업을-마치면-할-수-있는-것" aria-label="Permalink to &quot;수업을 마치면 할 수 있는 것&quot;">​</a></h2><ul><li>Token Stats 데이터가 어디서 오는지 설명할 수 있습니다(언제 기록되는지, 어떤 경우 누락되는지)</li><li>시간/일/주로 관찰 창을 전환하여 &quot;하루만 보는&quot; 오류 판단을 피합니다</li><li>&quot;모델별/계정별&quot; 두 가지 뷰에서 추세 차트로 이상치 피크를 찾습니다</li><li>Top 리스트로 가장 비싼 모델/계정을 찾고, 요청 로그로 돌아가 근본 원인을 찾습니다</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><ul><li>호출이 비싸졌다고 느끼지만, 모델이 바뀌었는지, 계정이 바뀌었는지, 특정 날 사용량이 급증한 것인지 모릅니다</li><li><code>X-Mapped-Model</code>을 보았지만, 통계가 어떤 모델 기준으로 계산되는지 확실하지 않습니다</li><li>Token Stats에서 간혹 0이거나 &quot;데이터 없음&quot;으로 나오는데, 트래픽이 없는 것인지 통계가 안 된 것인지 모릅니다</li></ul><h2 id="언제-이-기능을-사용해야-하나요" tabindex="-1">언제 이 기능을 사용해야 하나요 <a class="header-anchor" href="#언제-이-기능을-사용해야-하나요" aria-label="Permalink to &quot;언제 이 기능을 사용해야 하나요&quot;">​</a></h2><ul><li>비용 최적화를 할 때: &quot;가장 비싼 것&quot;을 먼저 정량화</li><li>급격한 제한/이상을 문제 해결할 때: 피크 시간대로 요청 로그를 대조</li><li>모델 라우팅/할당량 관리 구성 변경 후 비용이 예상대로 감소하는지 검증할 때</li></ul><h2 id="token-stats란-무엇인가" tabindex="-1">Token Stats란 무엇인가? <a class="header-anchor" href="#token-stats란-무엇인가" aria-label="Permalink to &quot;Token Stats란 무엇인가?&quot;">​</a></h2><p><strong>Token Stats</strong>는 Antigravity Tools의 로컬 사용량 통계 페이지입니다: 프록시가 요청을 전달한 후, 응답 JSON 또는 스트림 데이터에서 <code>usage/usageMetadata</code>의 토큰 수를 추출하려 시도하고, 각 요청을 계정 및 모델별로 로컬 SQLite(<code>token_stats.db</code>)에 기록한 다음, UI에서 시간/모델/계정별로 집계하여 표시합니다.</p><div class="info custom-block"><p class="custom-block-title">먼저 한 가지 쉽게 빠지는 포인트를 설명합니다</p><p>Token Stats의 &quot;모델&quot; 기준은 요청의 <code>model</code> 필드에서 옵니다(또는 Gemini의 <code>/v1beta/models/&lt;model&gt;</code> 경로 파싱), 라우팅 후의 <code>X-Mapped-Model</code>과 같지 않습니다.</p></div><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><ul><li>이미 프록시 호출을 한 번 실행했습니다(<code>/healthz</code> 헬스 체크에만 머물지 않음)</li><li>업스트림 응답이 파싱 가능한 토큰 사용량 필드를 반환합니다(그렇지 않으면 통계가 누락됨)</li></ul><div class="tip custom-block"><p class="custom-block-title">함께 읽을 것 권장</p><p>모델 매핑으로 <code>model</code>을 다른 물리적 모델로 라우팅하고 있다면, 먼저 **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/advanced/model-router/">모델 라우팅: 사용자 정의 매핑, 와일드카드 우선순위 및 프리셋 전략</a>**을 보고, 다시 돌아와서 &quot;통계 기준&quot;을 보면 더 직관적입니다.</p></div><h2 id="핵심-아이디어" tabindex="-1">핵심 아이디어 <a class="header-anchor" href="#핵심-아이디어" aria-label="Permalink to &quot;핵심 아이디어&quot;">​</a></h2><p>Token Stats 데이터 체인을 세 단계로 나눌 수 있습니다:</p><ol><li>프록시 미들웨어가 응답에서 토큰 사용량 추출(<code>usage</code>/<code>usageMetadata</code> 호환, 스트림도 파싱)</li><li>동시에 <code>account_email + input_tokens + output_tokens</code>를 얻으면, 로컬 SQLite(<code>token_stats.db</code>)에 기록</li><li>UI는 Tauri <code>invoke(get_token_stats_*)</code>로 집계 데이터를 가져와서 시간/일/주로 표시</li></ol><h2 id="따라해보기" tabindex="-1">따라해보기 <a class="header-anchor" href="#따라해보기" aria-label="Permalink to &quot;따라해보기&quot;">​</a></h2><h3 id="_1단계-먼저-트래픽-이-있는지-확인" tabindex="-1">1단계: 먼저 &quot;트래픽&quot;이 있는지 확인 <a class="header-anchor" href="#_1단계-먼저-트래픽-이-있는지-확인" aria-label="Permalink to &quot;1단계: 먼저 &quot;트래픽&quot;이 있는지 확인&quot;">​</a></h3><p><strong>이유</strong> Token Stats 통계는 실제 요청에서 옵니다. 프록시만 시작하고 모델 요청을 한 번도 보내지 않으면, 페이지가 &quot;데이터 없음&quot;을 표시합니다.</p><p>방법: **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">로컬 리버스 프록시 시작 및 첫 번째 클라이언트 연결</a>**에서 이미 검증된 호출 방법을 재사용하여 1-2회 요청을 보냅니다.</p><p><strong>볼 수 있는 것</strong>: Token Stats 페이지가 &quot;로딩 중/데이터 없음&quot;에서 차트나 리스트로 바뀝니다.</p><h3 id="_2단계-올바른-시간-창-선택-시간-일-주" tabindex="-1">2단계: 올바른 시간 창 선택(시간/일/주) <a class="header-anchor" href="#_2단계-올바른-시간-창-선택-시간-일-주" aria-label="Permalink to &quot;2단계: 올바른 시간 창 선택(시간/일/주)&quot;">​</a></h3><p><strong>이유</strong> 동일한 데이터라도 다른 창에서 보면 &quot;피크/추세&quot;가 완전히 다릅니다. UI의 세 가지 창에 대한 데이터 범위도 다릅니다:</p><ul><li>시간: 최근 24시간</li><li>일: 최근 7일</li><li>주: 최근 4주(추세 뷰는 최근 30일로 집계)</li></ul><p><strong>볼 수 있는 것</strong>: 전환 후 추세 차트의 가로축이 바뀝니다(시간은 &quot;시간&quot; 표시, 일은 &quot;월/일&quot;, 주는 &quot;년-W주차&quot;).</p><h3 id="_3단계-먼저-상단-총괄-보고-비용-규모-결정" tabindex="-1">3단계: 먼저 상단 총괄 보고 &quot;비용 규모&quot; 결정 <a class="header-anchor" href="#_3단계-먼저-상단-총괄-보고-비용-규모-결정" aria-label="Permalink to &quot;3단계: 먼저 상단 총괄 보고 &quot;비용 규모&quot; 결정&quot;">​</a></h3><p><strong>이유</strong> 총괄 카드가 먼저 세 가지 질문에 답할 수 있습니다: 총량이 큰지, 입력/출력 비율이 이상한지, 참여한 계정/모델이 갑자기 늘어났는지.</p><p>다음 항목을 중점적으로 보세요:</p><ul><li>총 토큰(<code>total_tokens</code>)</li><li>입력/출력 토큰(<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>활성 계정 수(<code>unique_accounts</code>)</li><li>사용 모델 수(UI는 &quot;모델별 통계 리스트&quot;의 길이를 직접 사용)</li></ul><p><strong>볼 수 있는 것</strong>: &quot;활성 계정 수&quot;가 급증하면 일반적으로 짧은 시간 내에 더 많은 계정을 실행했다는 의미입니다(예: 로테이션 전략으로 전환).</p><h3 id="_4단계-모델별-계정별-사용-추세-로-이상치-피크-잡기" tabindex="-1">4단계: &quot;모델별/계정별 사용 추세&quot;로 이상치 피크 잡기 <a class="header-anchor" href="#_4단계-모델별-계정별-사용-추세-로-이상치-피크-잡기" aria-label="Permalink to &quot;4단계: &quot;모델별/계정별 사용 추세&quot;로 이상치 피크 잡기&quot;">​</a></h3><p><strong>이유</strong> 추세 차트는 &quot;갑자기 비싸지는 것&quot;을 잡기에 가장 적합한 입구입니다. 원인을 먼저 알 필요 없이 &quot;어느 날/어느 시간에 급증했는지&quot; 먼저 표시하세요.</p><p>방법:</p><ol><li>추세 차트 오른쪽 상단에서 &quot;모델별 / 계정별&quot; 전환</li><li>마우스를 올려서(Tooltip) Top 값을 보고, &quot;갑자기 첫 번째로 올라간 것&quot;을 우선적으로 주목</li></ol><p><strong>볼 수 있는 것</strong>:</p><ul><li>모델별: 특정 모델이 특정 시간대에 급증</li><li>계정별: 특정 계정이 특정 시간대에 급증</li></ul><h3 id="_5단계-top-리스트로-가장-비싼-대상-을-고정" tabindex="-1">5단계: Top 리스트로 &quot;가장 비싼 대상&quot;을 고정 <a class="header-anchor" href="#_5단계-top-리스트로-가장-비싼-대상-을-고정" aria-label="Permalink to &quot;5단계: Top 리스트로 &quot;가장 비싼 대상&quot;을 고정&quot;">​</a></h3><p><strong>이유</strong> 추세 차트는 &quot;언제 이상한지&quot; 알려주고, Top 리스트는 &quot;가장 비싼 것이 누구인지&quot; 알려줍니다. 이 두 가지를 교차하면 빠르게 문제 해결 범위를 찾을 수 있습니다.</p><p>방법:</p><ul><li>&quot;모델별&quot; 뷰에서 &quot;모델별 상세 통계&quot; 테이블의 <code>total_tokens / request_count / 비율</code> 보기</li><li>&quot;계정별&quot; 뷰에서 &quot;계정 상세 통계&quot; 테이블의 <code>total_tokens / request_count</code> 보기</li></ul><p><strong>볼 수 있는 것</strong>: 가장 비싼 모델/계정이 앞에 있고, <code>request_count</code>가 &quot;한 번에 특별히 비싼지&quot; &quot;횟수가 특별히 많은지&quot; 구분할 수 있습니다.</p><h3 id="_6단계-선택-사항-token-stats-db-찾기-백업-대조" tabindex="-1">6단계(선택 사항): <code>token_stats.db</code> 찾기, 백업/대조 <a class="header-anchor" href="#_6단계-선택-사항-token-stats-db-찾기-백업-대조" aria-label="Permalink to &quot;6단계(선택 사항): `token_stats.db` 찾기, 백업/대조&quot;">​</a></h3><p><strong>이유</strong> &quot;통계 누락&quot;을 의심하거나 오프라인 분석을 하고 싶을 때, SQLite 파일을 직접 가져오는 것이 가장 확실합니다.</p><p>방법: Settings의 Advanced 영역에서 &quot;데이터 디렉터리 열기&quot;를 클릭하면 데이터 디렉터리에서 <code>token_stats.db</code>를 찾을 수 있습니다.</p><p><strong>볼 수 있는 것</strong>: 파일 목록에 <code>token_stats.db</code>가 있습니다(파일명은 백엔드에서 하드코딩됨).</p><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>Token Stats 통계가 &quot;응답의 usage/usageMetadata 추출 후 로컬 SQLite에 저장&quot;이라는 것을 명확히 설명할 수 있습니다. 클라우드 청구가 아닙니다.</li><li>&quot;모델별/계정별&quot; 두 가지 추세 뷰에서 구체적인 피크 시간대를 가리킬 수 있습니다.</li><li>Top 리스트로 실행 가능한 문제 해결 결론을 줄 수 있습니다: 먼저 어느 모델 또는 계정을 검토할지.</li></ul><h2 id="함정-경고" tabindex="-1">함정 경고 <a class="header-anchor" href="#함정-경고" aria-label="Permalink to &quot;함정 경고&quot;">​</a></h2><table tabindex="0"><thead><tr><th>현상</th><th>일반적인 원인</th><th>할 수 있는 것</th></tr></thead><tbody><tr><td>Token Stats가 &quot;데이터 없음&quot; 표시</td><td>실제 모델 요청이 없음; 또는 업스트림 응답에 파싱 가능한 토큰 필드가 없음</td><td>먼저 검증된 클라이언트로 요청 보내기; 응답에 <code>usage/usageMetadata</code>가 포함되어 있는지 확인</td></tr><tr><td>통계가 &quot;모델&quot;별로 보이지 않음</td><td>통계 기준은 요청의 <code>model</code>을 사용하고, <code>X-Mapped-Model</code>이 아님</td><td>모델 라우팅을 &quot;요청 모델 -&gt; 매핑 모델&quot;로 간주; 통계는 &quot;요청 모델&quot;을 봄</td></tr><tr><td>계정 차원 누락</td><td><code>X-Account-Email</code>을 얻고 토큰 사용량을 파싱할 때만 기록됨</td><td>요청이 실제 계정 풀에 도달했는지 확인; 다음 요청 로그/응답 헤더와 대조</td></tr><tr><td>Proxy Monitor 활성화 후 통계가 너무 큼</td><td>Proxy Monitor 활성화 시, 각 요청의 토큰이 두 번 기록됨</td><td>알려진 구현 세부 사항으로 상대적 추세 분석에는 영향 없음; 정확한 값이 필요하면 Monitor를 일시적으로 비활성화하고 다시 측정</td></tr></tbody></table><h2 id="이-수업-요약" tabindex="-1">이 수업 요약 <a class="header-anchor" href="#이-수업-요약" aria-label="Permalink to &quot;이 수업 요약&quot;">​</a></h2><ul><li>Token Stats의 핵심 가치는 &quot;비용 문제를 정량화&quot;하는 것입니다. 먼저 위치를 지정한 다음 최적화합니다.</li><li>통계 기록 시 계정과 토큰 사용량은 필수입니다. 모델이 누락되면 <code>&quot;unknown&quot;</code>으로 기록됩니다(기록 방지하지 않음).</li><li>더 세밀한 비용 제어를 하려면, 다음은 일반적으로 모델 라우팅 또는 할당량 관리로 돌아갑니다.</li></ul><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서는 긴 세션의 &quot;隐性 안정성 문제&quot;를 해결합니다: <strong><a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/advanced/context-compression/">긴 세션 안정성: 컨텍스트 압축, 서명 캐시 및 도구 결과 압축</a></strong>.</p></blockquote><p>배우게 될 것:</p><ul><li>세 가지 점진적 컨텍스트 압축이 각각 무엇을 하는지</li><li>왜 &quot;서명 캐시&quot;가 400 서명 오류를 줄일 수 있는지</li><li>도구 결과 압축은 무엇을 삭제하고 무엇을 유지하는지</li></ul><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>펼쳐서 소스 코드 위치 확인</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Token Stats UI: 시간 창/뷰 전환 및 데이터 가져오기</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>Token Stats UI: 빈 데이터 프롬프트(&quot;데이터 없음&quot;)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>토큰 사용량 추출: 요청에서 model 파싱, 응답에서 usage/usageMetadata 파싱</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>토큰 사용량 추출: 스트림 및 JSON 응답에서 usage 필드 파싱</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Token Stats 기록 지점: 계정+토큰 얻기 후 SQLite에 기록</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>데이터베이스 파일명 및 테이블 구조: <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>기록 로직: <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>쿼리 로직: 시간/일/주, 계정별/모델별, 추세 및 총괄</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Tauri 명령: <code>get_token_stats_*</code>가 프론트엔드에 노출</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>애플리케이션 시작 시 Token Stats DB 초기화</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>설정 페이지: 데이터 디렉터리 가져오기/열기(<code>token_stats.db</code> 찾기용)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',59)])])}const b=o(d,[["render",l]]);export{h as __pageData,b as default};
